import com.peakcommerce.promo.model.AppliedPromotion;
import com.peakcommerce.promo.model.CartContext;
import com.peakcommerce.promo.model.PromotionCandidate;
import com.peakcommerce.promo.model.PromotionEvaluationResult;
import com.peakcommerce.promo.model.PromotionEvaluationTrace;
import com.peakcommerce.promo.model.StackabilityDecision;
import com.peakcommerce.promo.model.StackabilityPolicy;
import com.peakcommerce.promo.model.TimeWindow;
import org.springframework.stereotype.Component;

import java.math.BigDecimal;
import java.time.Clock;
import java.time.Instant;
import java.time.ZoneId;
import java.util.ArrayList;
import java.util.Collection;
import java.util.Comparator;
import java.util.EnumSet;
import java.util.HashSet;
import java.util.List;
import java.util.Objects;
import java.util.Set;

@Component
public class StackabilityPolicyEvaluator {

    private static final ZoneId PRIMARY_BUSINESS_ZONE = ZoneId.of("Asia/Singapore");

    private final Clock clock;

    public StackabilityPolicyEvaluator() {
        this(Clock.system(PRIMARY_BUSINESS_ZONE));
    }

    public StackabilityPolicyEvaluator(Clock clock) {
        this.clock = Objects.requireNonNull(clock, "clock");
    }

    public PromotionEvaluationResult evaluate(
            CartContext cartContext,
            Collection<PromotionCandidate> candidates,
            Collection<AppliedPromotion> alreadyAppliedPromotions) {

        Objects.requireNonNull(cartContext, "cartContext");
        Objects.requireNonNull(candidates, "candidates");
        Objects.requireNonNull(alreadyAppliedPromotions, "alreadyAppliedPromotions");

        Instant evaluationTime = cartContext.requestedAt() != null ? cartContext.requestedAt() : clock.instant();
        List<PromotionCandidate> orderedCandidates = new ArrayList<>(candidates);
        orderedCandidates.sort(candidateComparator());

        List<AppliedPromotion> accepted = new ArrayList<>(alreadyAppliedPromotions);
        List<StackabilityDecision> decisions = new ArrayList<>();
        EvaluationState state = EvaluationState.from(alreadyAppliedPromotions);

        for (PromotionCandidate candidate : orderedCandidates) {
            StackabilityDecision decision = evaluateCandidate(cartContext, candidate, accepted, state, evaluationTime);
            decisions.add(decision);
            if (decision.isAccepted()) {
                AppliedPromotion appliedPromotion = toAppliedPromotion(candidate);
                accepted.add(appliedPromotion);
                state.add(candidate);
            }
        }

        return new PromotionEvaluationResult(
                cartContext.cartId(),
                cartContext.customerId(),
                cartContext.correlationId(),
                evaluationTime,
                List.copyOf(accepted),
                List.copyOf(decisions),
                new PromotionEvaluationTrace(
                        "promotion-pricing-service",
                        cartContext.correlationId(),
                        cartContext.cartId(),
                        cartContext.customerId(),
                        cartContext.tenantId(),
                        evaluationTime,
                        decisions)
        );
    }

    private StackabilityDecision evaluateCandidate(
            CartContext cartContext,
            PromotionCandidate candidate,
            List<AppliedPromotion> accepted,
            EvaluationState state,
            Instant evaluationTime) {

        if (candidate == null) {
            return StackabilityDecision.rejected("unknown", List.of("candidate_missing"));
        }

        List<String> reasons = new ArrayList<>();
        addIf(reasons, !candidate.enabled(), "promotion_disabled");
        addIf(reasons, state.promotionIds.contains(candidate.promotionId()), "promotion_already_applied");
        addIf(reasons, !isWithinWindow(candidate.activeWindow(), evaluationTime), "outside_campaign_window");
        addIf(reasons, !isWithinWindow(candidate.checkoutWindow(), evaluationTime), "outside_checkout_window");
        addIf(reasons, candidate.tenantId() != null && !candidate.tenantId().equals(cartContext.tenantId()), "tenant_scope_mismatch");
        addIf(reasons, candidate.market() != null && !candidate.market().equalsIgnoreCase(cartContext.market()), "market_scope_mismatch");
        addIf(reasons, candidate.currency() != null && !candidate.currency().equalsIgnoreCase(cartContext.currency()), "currency_scope_mismatch");
        addIf(reasons, belowMinimumSubtotal(cartContext, candidate), "minimum_subtotal_not_met");
        addIf(reasons, aboveMaximumSubtotal(cartContext, candidate), "maximum_subtotal_exceeded");
        addIf(reasons, candidate.maxStackedPromotions() != null && accepted.size() >= candidate.maxStackedPromotions(), "candidate_stack_limit_reached");
        addIf(reasons, cartContext.maxPromotionsAllowed() != null && accepted.size() >= cartContext.maxPromotionsAllowed(), "cart_stack_limit_reached");

        StackabilityPolicy policy = candidate.stackabilityPolicy();
        if (policy == null) {
            reasons.add("missing_stackability_policy");
        } else {
            applyPolicyChecks(candidate, accepted, state, policy, reasons);
        }

        return reasons.isEmpty()
                ? StackabilityDecision.accepted(candidate.promotionId(), List.of("accepted"))
                : StackabilityDecision.rejected(candidate.promotionId(), List.copyOf(reasons));
    }

    private void applyPolicyChecks(
            PromotionCandidate candidate,
            List<AppliedPromotion> accepted,
            EvaluationState state,
            StackabilityPolicy policy,
            List<String> reasons) {

        if (policy.exclusive()) {
            addIf(reasons, !accepted.isEmpty(), "exclusive_promotion_cannot_stack");
            return;
        }

        BenefitType candidateBenefitType = resolveBenefitType(candidate.benefitType());

        addIf(reasons, policy.blockWithExclusiveApplied() && state.hasExclusive, "existing_exclusive_promotion_blocks_stack");
        addIf(reasons, hasText(candidate.exclusionGroup()) && state.exclusionGroups.contains(candidate.exclusionGroup()), "exclusion_group_conflict");
        addIf(reasons, !policy.allowedPromotionIds().isEmpty() && accepted.stream().anyMatch(a -> !policy.allowedPromotionIds().contains(a.promotionId())), "stack_not_in_allow_list");
        addIf(reasons, !policy.blockedPromotionIds().isEmpty() && accepted.stream().anyMatch(a -> policy.blockedPromotionIds().contains(a.promotionId())), "blocked_promotion_conflict");
        addIf(reasons, !policy.allowedBenefitTypes().isEmpty() && !policy.allowedBenefitTypes().contains(candidateBenefitType) && !accepted.isEmpty(), "candidate_benefit_type_not_allowed");
        addIf(reasons, !policy.blockedBenefitTypes().isEmpty() && policy.blockedBenefitTypes().contains(candidateBenefitType) && !accepted.isEmpty(), "candidate_benefit_type_blocked");
        addIf(reasons, !policy.allowMultipleOrderDiscounts() && candidateBenefitType == BenefitType.ORDER_DISCOUNT && state.benefitTypes.contains(BenefitType.ORDER_DISCOUNT), "multiple_order_discounts_not_allowed");
        addIf(reasons, !policy.allowCouponWithAutoApplied() && candidate.couponBased() && state.hasAutoApplied, "coupon_cannot_stack_with_auto_applied");
        addIf(reasons, !policy.allowAutoAppliedWithCoupon() && !candidate.couponBased() && state.hasCouponBased, "auto_applied_cannot_stack_with_coupon");
        addIf(reasons, !policy.allowShippingDiscountWithOrderDiscount() && candidateBenefitType == BenefitType.SHIPPING_DISCOUNT && state.benefitTypes.contains(BenefitType.ORDER_DISCOUNT), "shipping_discount_cannot_stack_with_order_discount");
        addIf(reasons, !policy.allowItemDiscountWithBundle() && candidateBenefitType == BenefitType.ITEM_DISCOUNT && state.benefitTypes.contains(BenefitType.BUNDLE), "item_discount_cannot_stack_with_bundle");
    }

    private boolean belowMinimumSubtotal(CartContext cartContext, PromotionCandidate candidate) {
        return candidate.minimumSubtotal() != null
                && cartContext.subtotal() != null
                && cartContext.subtotal().compareTo(candidate.minimumSubtotal()) < 0;
    }

    private boolean aboveMaximumSubtotal(CartContext cartContext, PromotionCandidate candidate) {
        return candidate.maximumSubtotal() != null
                && cartContext.subtotal() != null
                && cartContext.subtotal().compareTo(candidate.maximumSubtotal()) > 0;
    }

    private boolean isWithinWindow(TimeWindow window, Instant evaluationTime) {
        return window == null
                || ((window.startAt() == null || !evaluationTime.isBefore(window.startAt()))
                && (window.endAt() == null || evaluationTime.isBefore(window.endAt())));
    }

    private Comparator<PromotionCandidate> candidateComparator() {
        return Comparator.comparingInt(this::priorityOrDefault)
                .reversed()
                .thenComparing(this::discountValueOrZero)
                .reversed()
                .thenComparing(PromotionCandidate::promotionId, Comparator.nullsLast(String::compareTo));
    }

    private int priorityOrDefault(PromotionCandidate candidate) {
        return candidate.priority() == null ? 0 : candidate.priority();
    }

    private BigDecimal discountValueOrZero(PromotionCandidate candidate) {
        return candidate.estimatedDiscount() == null ? BigDecimal.ZERO : candidate.estimatedDiscount();
    }

    private AppliedPromotion toAppliedPromotion(PromotionCandidate candidate) {
        return new AppliedPromotion(
                candidate.promotionId(),
                candidate.campaignId(),
                candidate.exclusionGroup(),
                candidate.couponBased(),
                candidate.stackabilityPolicy() != null && candidate.stackabilityPolicy().exclusive(),
                resolveBenefitType(candidate.benefitType()).name(),
                candidate.estimatedDiscount()
        );
    }

    private BenefitType resolveBenefitType(String rawType) {
        if (!hasText(rawType)) {
            return BenefitType.UNKNOWN;
        }
        try {
            return BenefitType.valueOf(rawType.trim().toUpperCase());
        } catch (IllegalArgumentException ex) {
            return BenefitType.UNKNOWN;
        }
    }

    private void addIf(List<String> reasons, boolean condition, String reason) {
        if (condition) {
            reasons.add(reason);
        }
    }

    private boolean hasText(String value) {
        return value != null && !value.isBlank();
    }

    private static final class EvaluationState {
        private final Set<String> promotionIds = new HashSet<>();
        private final Set<String> exclusionGroups = new HashSet<>();
        private final EnumSet<BenefitType> benefitTypes = EnumSet.noneOf(BenefitType.class);
        private boolean hasExclusive;
        private boolean hasCouponBased;
        private boolean hasAutoApplied;

        static EvaluationState from(Collection<AppliedPromotion> appliedPromotions) {
            EvaluationState state = new EvaluationState();
            for (AppliedPromotion applied : appliedPromotions) {
                if (applied == null) {
                    continue;
                }
                if (state.hasText(applied.promotionId())) {
                    state.promotionIds.add(applied.promotionId());
                }
                if (state.hasText(applied.exclusionGroup())) {
                    state.exclusionGroups.add(applied.exclusionGroup());
                }
                if (applied.benefitType() != null) {
                    state.benefitTypes.add(state.resolveBenefitType(applied.benefitType()));
                }
                state.hasExclusive |= applied.exclusive();
                state.hasCouponBased |= applied.couponBased();
                state.hasAutoApplied |= !applied.couponBased();
            }
            return state;
        }

        void add(PromotionCandidate candidate) {
            if (hasText(candidate.promotionId())) {
                promotionIds.add(candidate.promotionId());
            }
            if (hasText(candidate.exclusionGroup())) {
                exclusionGroups.add(candidate.exclusionGroup());
            }
            benefitTypes.add(resolveBenefitType(candidate.benefitType()));
            hasExclusive |= candidate.stackabilityPolicy() != null && candidate.stackabilityPolicy().exclusive();
            hasCouponBased |= candidate.couponBased();
            hasAutoApplied |= !candidate.couponBased();
        }

        private BenefitType resolveBenefitType(String rawType) {
            if (!hasText(rawType)) {
                return BenefitType.UNKNOWN;
            }
            try {
                return BenefitType.valueOf(rawType.trim().toUpperCase());
            } catch (IllegalArgumentException ex) {
                return BenefitType.UNKNOWN;
            }
        }

        private boolean hasText(String value) {
            return value != null && !value.isBlank();
        }
    }

    private enum BenefitType {
        ORDER_DISCOUNT,
        ITEM_DISCOUNT,
        SHIPPING_DISCOUNT,
        BUNDLE,
        GIFT,
        UNKNOWN
    }
}
